// Button.stories.tsx
export default { component: Button, parameters: { a11y: { test: 'error' } } };

export const Default = { args: { children: 'Save' } };
export const Hover = { args: { children: 'Save' }, parameters: { pseudo: { hover: true } } };
export const Focus = { args: { children: 'Save' }, parameters: { pseudo: { focus: true } } };
export const Disabled = { args: { children: 'Save', disabled: true } };
export const Loading = { args: { children: 'Saving...', isLoading: true } };
export const Error = { args: { children: 'Retry', tone: 'danger' } };
export const Dark = { args: { children: 'Save' }, parameters: { theme: 'dark' } };
// 'empty' and 'success' documented as N/A in README

// Button.stories.tsx — single happy-path story; no a11y; hard-coded styles
export default { component: Button };
export const Default = {
  args: { children: 'Save', style: { backgroundColor: '#0066cc', padding: '12px' } },
};
